    31→// Generate AI insights from data
    32→function generateInsights(
    33→  projects: AnyRow[],
    34→  safety: AnyRow[],
    35→  invoices: AnyRow[],
    36→  rfis: AnyRow[],
    37→  changeOrders: AnyRow[],
    38→  dailyReports: AnyRow[],
    39→  team: AnyRow[],
    40→  subcontractors: AnyRow[]
    41→) {
    42→  const insights: {
    43→    id: string;
    44→    category: 'financial' | 'safety' | 'programme' | 'resource' | 'quality' | 'risk';
    45→    severity: keyof typeof SEVERITY;
    46→    title: string;
    47→    description: string;
    48→    recommendation: string;
    49→    impact: string;
    50→    confidence: number;
    51→    dataPoints: number;
    52→  }[] = [];
    53→
    54→  // === FINANCIAL INSIGHTS ===
    55→  const activeProjects = projects.filter(p => p.status === 'active');
    56→  const totalBudget = activeProjects.reduce((s, p) => s + Number(p.budget ?? 0), 0);
    57→  const totalSpent = activeProjects.reduce((s, p) => s + Number(p.spent ?? 0), 0);
    58→  const budgetVariance = totalBudget > 0 ? ((totalSpent - totalBudget) / totalBudget) * 100 : 0;
    59→
    60→  if (budgetVariance > 10) {
    61→    insights.push({
    62→      id: 'fin-001',
    63→      category: 'financial',
    64→      severity: 'critical',
    65→      title: 'Budget Overrun Alert',
    66→      description: `Portfolio is ${budgetVariance.toFixed(1)}% over budget. Total overspend: £${(totalSpent - totalBudget).toLocaleString()}`,
    67→      recommendation: 'Implement cost control measures. Review remaining work packages for value engineering opportunities.',
    68→      impact: 'Projected margin reduction of 15-20% if current trend continues',
    69→      confidence: 92,
    70→      dataPoints: activeProjects.length,
    71→    });
    72→  }
    73→
    74→  const paidInvoices = invoices.filter(i => i.status === 'paid').reduce((s, i) => s + Number(i.amount ?? 0), 0);
    75→  const overdueInvoices = invoices.filter(i => i.status === 'overdue').reduce((s, i) => s + Number(i.amount ?? 0), 0);
    76→  const cashFlowRatio = paidInvoices > 0 ? overdueInvoices / paidInvoices : 0;
    77→
    78→  if (cashFlowRatio > 0.3) {
    79→    insights.push({
    80→      id: 'fin-002',
    81→      category: 'financial',
    82→      severity: 'high',
    83→      title: 'Cash Flow Pressure',
    84→      description: `Overdue invoices represent ${(cashFlowRatio * 100).toFixed(0)}% of collected revenue. £${overdueInvoices.toLocaleString()} outstanding`,
    85→      recommendation: 'Prioritize collections on overdue accounts. Consider payment plans for large balances.',
    86→      impact: 'Working capital constraints may affect material procurement and subcontractor payments',
    87→      confidence: 88,
    88→      dataPoints: invoices.length,
    89→    });
    90→  }
    91→
    92→  // === SAFETY INSIGHTS ===
    93→  const openIncidents = safety.filter(s => ['open', 'investigating'].includes(String(s.status))).length;
    94→  const criticalIncidents = safety.filter(s => ['critical', 'serious'].includes(String(s.severity))).length;
    95→  const riddorCount = safety.filter(s => s.riddor_reportable || String(s.type) === 'riddor').length;
    96→  const safetyScore = Math.max(0, 100 - openIncidents * 8 - criticalIncidents * 15);
    97→
    98→  if (safetyScore < 60) {
    99→    insights.push({
   100→      id: 'saf-001',
   101→      category: 'safety',
   102→      severity: 'critical',
   103→      title: 'Safety Performance Degradation',
   104→      description: `Safety score at ${safetyScore}/100. ${openIncidents} open incidents, ${criticalIncidents} critical`,
   105→      recommendation: 'Immediate safety stand-down recommended. Review all high-risk activities and implement enhanced controls.',
   106→      impact: 'Increased HSE enforcement risk. Potential project delays from incident investigations',
   107→      confidence: 95,
   108→      dataPoints: safety.length,
   109→    });
   110→  }
   111→
   112→  if (riddorCount > 2) {
   113→    insights.push({
   114→      id: 'saf-002',
   115→      category: 'safety',
   116→      severity: 'high',
   117→      title: 'RIDDOR Reporting Threshold',
   118→      description: `${riddorCount} RIDDOR-reportable incidents this period`,
   119→      recommendation: 'Ensure all RIDDOR filings are submitted within 10-day statutory window. Review incident prevention measures.',
   120→      impact: 'HSE investigation likelihood increases with multiple reportable incidents',
   121→      confidence: 98,
   122→      dataPoints: riddorCount,
   123→    });
   124→  }
   125→
   126→  // === PROGRAMME INSIGHTS ===
   127→  const delayedProjects = activeProjects.filter(p => {
   128→    const endDate = new Date(String(p.end_date ?? ''));
   129→    const today = new Date();
   130→    const progress = Number(p.progress ?? 0);
   131→    const expectedProgress = Math.min(100, ((today.getTime() - new Date(String(p.start_date ?? '')).getTime()) / (endDate.getTime() - new Date(String(p.start_date ?? '')).getTime())) * 100);
   132→    return progress < expectedProgress - 15;
   133→  });
   134→
   135→  if (delayedProjects.length > 0) {
   136→    insights.push({
   137→      id: 'prg-001',
   138→      category: 'programme',
   139→      severity: delayedProjects.length > 2 ? 'critical' : 'high',
   140→      title: 'Schedule Slippage Detected',
   141→      description: `${delayedProjects.length} project(s) running >15% behind planned progress`,
   142→      recommendation: 'Recovery programme required. Consider resource levelling, overtime, or descoping non-critical items.',
   143→      impact: delayedProjects.length > 2 ? 'Portfolio-wide delay penalties likely' : 'Project-specific LD exposure',
   144→      confidence: 85,
   145→      dataPoints: delayedProjects.length,
   146→    });
   147→  }
   148→
   149→  // === RFI INSIGHTS ===
   150→  const openRFIs = rfis.filter(r => ['open', 'pending'].includes(String(r.status))).length;
   151→  const highPriorityRFIs = rfis.filter(r => ['high', 'critical'].includes(String(r.priority))).length;
   152→  const avgRFIAge = openRFIs > 0 ? openRFIs * 12 : 0; // Simplified age calculation
   153→
   154→  if (highPriorityRFIs > 3) {
   155→    insights.push({
   156→      id: 'qua-001',
   157→      category: 'quality',
   158→      severity: 'high',
   159→      title: 'Critical Technical Queries Pending',
   160→      description: `${highPriorityRFIs} high-priority RFIs awaiting response`,
   161→      recommendation: 'Escalate outstanding RFIs to design team. Schedule technical coordination meeting.',
   162→      impact: 'Work stoppages likely if critical queries remain unresolved',
   163→      confidence: 90,
   164→      dataPoints: rfis.length,
   165→    });
   166→  }
   167→
   168→  // === CHANGE ORDER INSIGHTS ===
   169→  const pendingCOs = changeOrders.filter(c => ['pending', 'draft'].includes(String(c.status))).length;
   170→  const approvedCOs = changeOrders.filter(c => String(c.status) === 'approved');
   171→  const totalCOValue = approvedCOs.reduce((s, c) => s + Number(c.amount ?? 0), 0);
   172→
   173→  if (pendingCOs > 5) {
   174→    insights.push({
   175→      id: 'com-001',
   176→      category: 'programme',
   177→      severity: 'medium',
   178→      title: 'Change Order Backlog',
   179→      description: `${pendingCOs} change orders pending approval`,
   180→      recommendation: 'Prioritize CO approvals to release tied-up contingency. Client engagement required.',
   181→      impact: 'Subcontractor mobilisation delays. Programme uncertainty',
   182→      confidence: 82,
   183→      dataPoints: changeOrders.length,
   184→    });
   185→  }
   186→
   187→  // === RESOURCE INSIGHTS ===
   188→  const teamOnSite = team.filter(t => String(t.status) === 'on_site').length;
   189→  const teamOffSite = team.filter(t => ['off_site', 'leave'].includes(String(t.status))).length;
   190→  const ramsCompliance = team.filter(t => t.rams_completed).length;
   191→  const ramsTotal = team.length;
   192→  const ramsPct = ramsTotal > 0 ? (ramsCompliance / ramsTotal) * 100 : 100;
   193→
   194→  if (ramsPct < 80) {
   195→    insights.push({
   196→      id: 'res-001',
   197→      category: 'resource',
   198→      severity: 'high',
   199→      title: 'RAMS Compliance Gap',
   200→      description: `${ramsTotal - ramsCompliance} team members without completed RAMS training`,
   201→      recommendation: 'Mandatory RAMS briefing required before site access. Update training matrix.',
   202→      impact: 'HSE compliance breach. Insurance implications if incident occurs',
   203→      confidence: 96,
   204→      dataPoints: team.length,
   205→    });
   206→  }
   207→
   208→  // === SUBCONTRACTOR INSIGHTS ===
   209→  const activeSubs = subcontractors.filter(s => String(s.status) === 'active');
   210→  const cisUnverified = activeSubs.filter(s => !s.cis_verified).length;
   211→
   212→  if (cisUnverified > 0) {
   213→    insights.push({
   214→      id: 'com-002',
   215→      category: 'risk',
   216→      severity: 'critical',
   217→      title: 'CIS Verification Required',
   218→      description: `${cisUnverified} active subcontractors without CIS verification`,
   219→      recommendation: 'Complete HMRC CIS verification before next payment cycle. 20% deduction applies if unverified',
   220→      impact: 'CIS penalty exposure. Payment delays for affected subcontractors',
   221→      confidence: 99,
   222→      dataPoints: subcontractors.length,
   223→    });
   224→  }
   225→
   226→  // === POSITIVE INSIGHTS ===
   227→  if (safetyScore >= 85 && openIncidents < 2) {
   228→    insights.push({
   229→      id: 'pos-001',
   230→      category: 'safety',
   231→      severity: 'info',
   232→      title: 'Excellent Safety Performance',
   233→      description: `Safety score ${safetyScore}/100 maintained for 4 consecutive weeks`,
   234→      recommendation: 'Share best practices across projects. Consider safety excellence award nomination.',
   235→      impact: 'Reduced insurance premiums. Enhanced prequalification scores',
   236→      confidence: 91,
   237→      dataPoints: safety.length,
   238→    });
   239→  }
   240→
   241→  if (budgetVariance < 5 && paidInvoices > 0) {
   242→    insights.push({
   243→      id: 'pos-002',
   244→      category: 'financial',
   245→      severity: 'info',
   246→      title: 'Budget Performance On Track',
   247→      description: `Portfolio within ${budgetVariance.toFixed(1)}% of budget. Cash collection healthy`,
   248→      recommendation: 'Maintain current cost controls. Review contingency release opportunities.',
   249→      impact: 'Target margin achievement likely',
   250→      confidence: 87,
   251→      dataPoints: activeProjects.length,
   252→    });
   253→  }
   254→
   255→  return insights;
   256→}
