   258→// Build trend data for charts
   259→function buildTrendData(insights: any[]) {
   260→  const categories = ['financial', 'safety', 'programme', 'resource', 'quality', 'risk'];
   261→  const severityWeights = { critical: 4, high: 3, medium: 2, low: 1, info: 0 };
   262→
   263→  return categories.map(cat => ({
   264→    category: cat.charAt(0).toUpperCase() + cat.slice(1),
   265→    critical: insights.filter(i => i.category === cat && i.severity === 'critical').length,
   266→    high: insights.filter(i => i.category === cat && i.severity === 'high').length,
   267→    medium: insights.filter(i => i.category === cat && i.severity === 'medium').length,
   268→    totalScore: insights.filter(i => i.category === cat).reduce((s, i) => s + severityWeights[i.severity as SeverityKey], 0),
   269→  }));
   270→}
