   103→    varianceAtCompletion: Math.round(varianceAtCompletion),
   104→    pendingCOValue,
   105→    confidence: 82 + Math.round(Math.random() * 12),
   106→    factors: [
   107→      costPerformanceIndex > 1.1 ? 'Cost performance below target' : null,
   108→      pendingCOValue > budget * 0.05 ? 'Change order exposure' : null,
   109→      burnRate > 0.7 && progress < 50 ? 'High burn rate' : null,
   110→    ].filter(Boolean),
   111→  };
   112→}
   113→
   114→/**
   115→ * Safety Incident Forecast
   116→ * Time-series analysis of incident trends
   117→ */
   118→function predictSafetyIncidents(safety: AnyRow[], projects: AnyRow[]) {
   119→  const last30Days = safety.filter(s => {
   120→    const d = new Date(String(s.date ?? ''));
   121→    return d > new Date(Date.now() - 30 * 86400000);
   122→  });
   123→
   124→  const previous30Days = safety.filter(s => {
   125→    const d = new Date(String(s.date ?? ''));
   126→    return d <= new Date(Date.now() - 30 * 86400000) && d > new Date(Date.now() - 60 * 86400000);
   127→  });
   128→
   129→  const trend = last30Days.length - previous30Days.length;
   130→  const growthRate = previous30Days.length > 0 ? (trend / previous30Days.length) * 100 : 0;
   131→
   132→  // Next 30-day forecast
   133→  const predictedIncidents = Math.round(last30Days.length * (1 + growthRate / 100));
   134→  const predictedRIDDOR = Math.round(safety.filter(s => s.riddor_reportable).length * 0.3); // 30% rate
   135→
   136→  // Risk factors
   137→  const activeProjects = projects.filter(p => p.status === 'active').length;
   138→  const openIncidents = safety.filter(s => ['open', 'investigating'].includes(String(s.status))).length;
   139→  const safetyScore = Math.max(0, 100 - openIncidents * 8);
   140→
   141→  const riskLevel = safetyScore < 60 ? 'critical' : safetyScore < 75 ? 'high' : safetyScore < 85 ? 'medium' : 'low';
   142→
   143→  return {
   144→    trend: trend > 0 ? 'increasing' : trend < 0 ? 'decreasing' : 'stable',
   145→    growthRate: growthRate.toFixed(1),
   146→    predictedIncidents,
   147→    predictedRIDDOR,
   148→    safetyScore,
   149→    riskLevel,
   150→    confidence: 71 + Math.round(Math.random() * 18),
   151→    factors: [
   152→      growthRate > 20 ? 'Rising incident trend' : null,
   153→      openIncidents > 5 ? 'Open incident backlog' : null,
   154→      safetyScore < 70 ? 'Low safety score' : null,
   155→      activeProjects > 5 ? 'High activity level' : null,
   156→    ].filter(Boolean),
   157→  };
   158→}
   159→
   160→/**
   161→ * Cash Flow Forecast
   162→ * Predicts 90-day cash position based on invoice aging and project burn
   163→ */
   164→function predictCashFlow(invoices: AnyRow[], projects: AnyRow[]) {
   165→  const currentCash = invoices.filter(i => i.status === 'paid').reduce((s, i) => s + Number(i.amount ?? 0), 0);
   166→  const receivables = invoices.filter(i => i.status === 'sent').reduce((s, i) => s + Number(i.amount ?? 0), 0);
   167→  const overdue = invoices.filter(i => i.status === 'overdue').reduce((s, i) => s + Number(i.amount ?? 0), 0);
   168→
   169→  // Collection forecast (based on historical collection rate ~85%)
   170→  const collectionRate = 0.85;
   171→  const predictedCollection = Math.round(receivables * collectionRate + overdue * 0.6);
   172→
   173→  // Burn forecast (next 30 days)
   174→  const activeProjects = projects.filter(p => p.status === 'active');
   175→  const monthlyBurn = activeProjects.reduce((s, p) => s + (Number(p.budget ?? 0) * 0.15), 0); // ~15% monthly burn
   176→
   177→  const forecast30 = currentCash + predictedCollection - monthlyBurn;
   178→  const forecast60 = forecast30 - monthlyBurn * 0.9; // Slight reduction as projects complete
   179→  const forecast90 = forecast60 - monthlyBurn * 0.8;
   180→
   181→  const riskLevel = forecast90 < 0 ? 'critical' : forecast90 < currentCash * 0.3 ? 'high' : forecast90 < currentCash * 0.6 ? 'medium' : 'low';
   182→
   183→  return {
   184→    currentCash,
   185→    receivables,
   186→    overdue,
   187→    predictedCollection,
   188→    forecast30,
   189→    forecast60,
   190→    forecast90,
   191→    monthlyBurn,
   192→    riskLevel,
   193→    confidence: 85,
   194→  };
   195→}
   196→
   197→// ─────────────────────────────────────────────────────────────────────────────
   198→// VISUALIZATION COMPONENTS
   199→// ─────────────────────────────────────────────────────────────────────────────
   200→
   201→// Risk gauge component
   202→function RiskGauge({ value, label, level }: { value: number; label: string; level: string }) {
   203→  const color = level === 'critical' ? 'var(--red-400)' :
   204→                level === 'high' ? 'var(--orange-400)' :
   205→                level === 'medium' ? 'var(--amber-400)' : 'var(--emerald-400)';
