                </thead>
                <tbody>
                  {predictions.delays.map((p, i) => (
                    <tr key={i} style={{ borderBottom: '1px solid var(--slate-800)' }}>
                      <td style={{ padding: '12px', fontFamily: 'var(--font-body)', fontSize: '13px', color: 'var(--slate-100)' }}>
